9	#define VERSION "1.0.3"
10	
11	#define _XOPEN_SOURCE 500 // for: usleep
12	#include <stdio.h>		  // defines: printf, puts, getchar
13	#include <stdlib.h>		  // defines: EXIT_SUCCESS
14	#include <string.h>		  // defines: strcmp
15	#include <unistd.h>		  // defines: STDIN_FILENO, usleep
16	#include <termios.h>	  // defines: termios, TCSANOW, ICANON, ECHO
17	#include <stdbool.h>	  // defines: true, false
18	#include <stdint.h>		  // defines: uint8_t, uint32_t
19	#include <time.h>		  // defines: time
20	#include <signal.h>		  // defines: signal, SIGINT
21	
22	#define SIZE 4
23	
24	// Specification helper: a file-scope mirror of the four local color schemes,
25	// used only inside getColors's contract to pin the exact output values.  A
26	// global const table is used (rather than an in-contract compound literal) so
27	// the postconditions stay cheap to evaluate and remain reachable within CBMC's
28	// bounded analysis depth.  Each row has 32 entries (== sizeof(original)).
29	static const uint8_t getColors_schemes[4][32] = {
30		{8, 255, 1, 255, 2, 255, 3, 255, 4, 255, 5, 255, 6, 255, 7, 255, 9, 0, 10, 0, 11, 0, 12, 0, 13, 0, 14, 0, 255, 0, 255, 0},
31		{232, 255, 234, 255, 236, 255, 238, 255, 240, 255, 242, 255, 244, 255, 246, 0, 248, 0, 249, 0, 250, 0, 251, 0, 252, 0, 253, 0, 254, 0, 255, 0},
32		{235, 255, 63, 255, 57, 255, 93, 255, 129, 255, 165, 255, 201, 255, 200, 255, 199, 255, 198, 255, 197, 255, 196, 255, 196, 255, 196, 255, 196, 255, 196, 255},
33		{255, 0, 254, 0, 253, 0, 252, 0, 251, 0, 250, 0, 249, 0, 248, 0, 246, 255, 244, 255, 242, 255, 240, 255, 238, 255, 236, 255, 234, 255, 232, 255}};
34	
35	// this function receives 2 pointers (indicated by *) so it can set their values
36	void getColors(uint8_t value, uint8_t scheme, uint8_t *foreground, uint8_t *background)
37	// scheme must index one of the four schemes (else schemes[scheme] reads out of
38	// bounds); both output locations must be writable.  The three conditions are
39	// stated as a single requires clause: fewer clauses means fewer assume steps,
40	// which keeps the postconditions reachable within CBMC's bounded depth.
41	__CPROVER_requires(scheme < 4 &&
42	                   __CPROVER_w_ok(foreground, sizeof(uint8_t)) &&
43	                   __CPROVER_w_ok(background, sizeof(uint8_t)))
44	__CPROVER_assigns(*foreground, *background)
45	// The outputs are exactly the indexed entries of the selected scheme.  The
46	// foreground index is the background index + 1 (foreground is always at an odd
47	// offset, background at the preceding even one); writing it that way shares the
48	// (value * 2) % 32 subexpression and keeps both postconditions cheap.
49	// Background is stated first so, under bounded depth, its postcondition is
50	// reached before the budget is exhausted.
51	__CPROVER_ensures(*background == getColors_schemes[scheme][value * 2 % 32])
52	__CPROVER_ensures(*foreground == getColors_schemes[scheme][value * 2 % 32 + 1])
53	{
54		uint8_t original[] = {8, 255, 1, 255, 2, 255, 3, 255, 4, 255, 5, 255, 6, 255, 7, 255, 9, 0, 10, 0, 11, 0, 12, 0, 13, 0, 14, 0, 255, 0, 255, 0};
55		uint8_t blackwhite[] = {232, 255, 234, 255, 236, 255, 238, 255, 240, 255, 242, 255, 244, 255, 246, 0, 248, 0, 249, 0, 250, 0, 251, 0, 252, 0, 253, 0, 254, 0, 255, 0};
56		uint8_t bluered[] = {235, 255, 63, 255, 57, 255, 93, 255, 129, 255, 165, 255, 201, 255, 200, 255, 199, 255, 198, 255, 197, 255, 196, 255, 196, 255, 196, 255, 196, 255, 196, 255};
57		uint8_t whiteblack[] = {255, 0, 254, 0, 253, 0, 252, 0, 251, 0, 250, 0, 249, 0, 248, 0, 246, 255, 244, 255, 242, 255, 240, 255, 238, 255, 236, 255, 234, 255, 232, 255};
58		uint8_t *schemes[] = {original, blackwhite, bluered, whiteblack};
59		// modify the 'pointed to' variables (using a * on the left hand of the assignment)
60		*foreground = *(schemes[scheme] + (1 + value * 2) % sizeof(original));
61		*background = *(schemes[scheme] + (0 + value * 2) % sizeof(original));
62		// alternatively we could have returned a struct with two variables
63	}
64	
65	// Specification helper: powers of ten as 64-bit values so the contract can
66	// pin the exact decimal-digit count.  A uint32_t can be at most 4294967295
67	// (10 digits), so we need 10^0 .. 10^10; the last entry overflows uint32_t,
68	// hence uint64_t.  A file-scope const table keeps the postcondition cheap to
69	// evaluate and reachable within CBMC's bounded analysis depth.
70	static const uint64_t getDigitCount_pow10[11] = {
71		1ULL, 10ULL, 100ULL, 1000ULL, 10000ULL, 100000ULL, 1000000ULL,
72		10000000ULL, 100000000ULL, 1000000000ULL, 10000000000ULL};
73	
74	uint8_t getDigitCount(uint32_t number)
75	// The return value is the number of decimal digits of `number`, with the
76	// edge case that 0 has one digit (the do-while body always runs once).  It
77	// therefore lies in 1..10 for any 32-bit input.  The two-sided bound pins the
78	// exact digit count: `number` is strictly below 10^r and (unless r==1) at
79	// least 10^(r-1), which uniquely identifies r.
80	__CPROVER_ensures(__CPROVER_return_value >= 1 && __CPROVER_return_value <= 10)
81	__CPROVER_ensures(number < getDigitCount_pow10[__CPROVER_return_value])
82	__CPROVER_ensures(__CPROVER_return_value == 1 ||
83	                  number >= getDigitCount_pow10[__CPROVER_return_value - 1])
84	{
85		uint8_t count = 0;
86		do
87		{
88			number /= 10;
89			count += 1;
90		} while (number);
91		return count;
92	}
93	
94	void drawBoard(uint8_t board[SIZE][SIZE], uint8_t scheme, uint32_t score)
95	// board must be readable; scheme must index one of the four color schemes (the
96	// precondition of every getColors call below); and each cell value must be at
97	// most 30 so that `1 << board[x][y]` (computed as a signed int) stays
98	// well-defined -- a larger exponent would shift into/past the sign bit (UB).
99	__CPROVER_requires(__CPROVER_is_fresh(board, sizeof(uint8_t[SIZE][SIZE])))
100	__CPROVER_requires(scheme < 4)
101	__CPROVER_requires(__CPROVER_forall {
102		int i; (0 <= i && i < SIZE) ==> __CPROVER_forall {
103			int j; (0 <= j && j < SIZE) ==> board[i][j] <= 30 } })
104	// drawBoard only emits text; it writes nothing but its own locals.  The empty
105	// assigns clause pins this down: the board (and all other pre-existing memory)
106	// is left untouched.
107	__CPROVER_assigns()
108	{
109		uint8_t x, y, fg, bg;
110		printf("\033[H"); // move cursor to 0,0
111		printf("2048.c %17u pts\n\n", score);
112		for (y = 0; y < SIZE; y++)
113		{
114			for (x = 0; x < SIZE; x++)
115			{
116				// send the addresses of the foreground and background variables,
117				// so that they can be modified by the getColors function
118				getColors(board[x][y], scheme, &fg, &bg);
119				printf("\033[38;5;%u;48;5;%um", fg, bg); // set color
120				printf("       ");
121				printf("\033[m"); // reset all modes
122			}
123			printf("\n");
124			for (x = 0; x < SIZE; x++)
125			{
126				getColors(board[x][y], scheme, &fg, &bg);
127				printf("\033[38;5;%u;48;5;%um", fg, bg); // set color
128				if (board[x][y] != 0)
129				{
130					uint32_t number = 1 << board[x][y];
131					uint8_t t = 7 - getDigitCount(number);
132					printf("%*s%u%*s", t - t / 2, "", number, t / 2, "");
133				}
134				else
135				{
136					printf("   ·   ");
137				}
138				printf("\033[m"); // reset all modes
139			}
140			printf("\n");
141			for (x = 0; x < SIZE; x++)
142			{
143				getColors(board[x][y], scheme, &fg, &bg);
144				printf("\033[38;5;%u;48;5;%um", fg, bg); // set color
145				printf("       ");
146				printf("\033[m"); // reset all modes
147			}
148			printf("\n");
149		}
150		printf("\n");
151		printf("        ←,↑,→,↓ or q        \n");
152		printf("\033[A"); // one line up
153	}
154	
155	uint8_t findTarget(uint8_t array[SIZE], uint8_t x, uint8_t stop)
156	// array must hold SIZE readable cells.  x indexes a board cell (x < SIZE).  The
157	// scan walks downward from x-1, decrementing t until it meets the stop barrier,
158	// so stop must sit strictly below x to avoid a wrap-around read past index 0.
159	// The sole exception is x == 0, which returns immediately with stop pinned to 0
160	// (this mirrors every call site in slideArray, where stop <= x always holds).
161	// The conditions are stated as one requires clause to keep the number of assume
162	// steps small, leaving the postconditions reachable within CBMC's bounded depth.
163	__CPROVER_requires(__CPROVER_is_fresh(array, SIZE * sizeof(uint8_t)) &&
164	                   x < SIZE &&
165	                   (x == 0 ? stop == 0 : stop < x))
166	__CPROVER_assigns()
167	// The chosen target never moves past the original cell and never drops below the
168	// stop barrier, so array[x] can always be slid safely into [stop, x].
169	__CPROVER_ensures(__CPROVER_return_value <= x)
170	__CPROVER_ensures(__CPROVER_return_value >= stop)
171	// Every cell strictly between the target and the origin is empty: the scan only
172	// slides over zeros, so it can never park below a non-empty tile.
173	__CPROVER_ensures(__CPROVER_forall {
174		unsigned char j;
175		(j > __CPROVER_return_value && j < x) ==> (array[j] == 0)
176	})
177	// Full characterization of where the scan parks.  Either it reaches the origin
178	// (r == x: blocked immediately by a differing tile, or x == 0), or it parks
179	// below the origin (r < x) for exactly one of three reasons: it sits on a tile
180	// equal to array[x] (a pending merge); it sits on an empty cell because it slid
181	// all the way to the stop barrier; or it sits on an empty cell just above a
182	// non-empty, differing tile (a plain move).
183	__CPROVER_ensures(
184		(__CPROVER_return_value == x &&
185			(x == 0 || (array[x - 1] != 0 && array[x - 1] != array[x])))
186		||
187		(__CPROVER_return_value < x &&
188			((array[__CPROVER_return_value] == array[x] &&
189				array[__CPROVER_return_value] != 0)
190			|| (array[__CPROVER_return_value] == 0 &&
191				(__CPROVER_return_value == stop
192				|| (array[__CPROVER_return_value - 1] != 0 &&
193					array[__CPROVER_return_value - 1] != array[x]))))))
194	{
195		uint8_t t;
196		// if the position is already on the first, don't evaluate
197		if (x == 0)
198		{
199			return x;
200		}
201		for (t = x - 1;; t--)
202		{
203			if (array[t] != 0)
204			{
205				if (array[t] != array[x])
206				{
207					// merge is not possible, take next position
208					return t + 1;
209				}
210				return t;
211			}
212			else
213			{
214				// we should not slide further, return this one
215				if (t == stop)
216				{
217					return t;
218				}
219			}
220		}
221		// we did not find a target
222		return x;
223	}
224	
225	/* Helpers for specifying `slideArray`.
226	 *
227	 *  - SA_PACKED: after the slide every tile sits left of every empty cell, i.e.
228	 *    an empty cell is never followed by a non-empty one (no gaps remain).  This
229	 *    is the defining shape of a completed slide and, crucially, it is cheap to
230	 *    evaluate -- three comparisons, no shifts, no `__CPROVER_old` snapshots --
231	 *    so it is reachable within CBMC's bounded analysis depth even after the four
232	 *    contract-replaced findTarget calls.  It is what kills the loop-bound and
233	 *    target-selection mutants (a slide that does nothing, or skips tiles, leaves
234	 *    a gap that this predicate detects).
235	 *
236	 *  - SA_SUM / SA_OLD_SUM: the conserved "tile mass".  An empty cell (0)
237	 *    contributes nothing, a tile of exponent v contributes its face value 2^v,
238	 *    and a merge replaces 2^v + 2^v by 2^(v+1) -- so the four-cell total is
239	 *    invariant across the call.  Face values come from a file-scope power-of-two
240	 *    table (rather than an in-contract shift) to keep the postcondition cheap;
241	 *    uint64_t and the <= 29 precondition together keep every entry and the sum
242	 *    free of overflow.  Indices are enumerated explicitly (no quantifier) so the
243	 *    expression stays straight-line. */
244	static const uint64_t SA_POW2[31] = {
245		0ULL, 2ULL, 4ULL, 8ULL, 16ULL, 32ULL, 64ULL, 128ULL, 256ULL, 512ULL,
246		1024ULL, 2048ULL, 4096ULL, 8192ULL, 16384ULL, 32768ULL, 65536ULL,
247		131072ULL, 262144ULL, 524288ULL, 1048576ULL, 2097152ULL, 4194304ULL,
248		8388608ULL, 16777216ULL, 33554432ULL, 67108864ULL, 134217728ULL,
249		268435456ULL, 536870912ULL, 1073741824ULL};
250	#define SA_PACKED \
251		((array[0] != 0 || array[1] == 0) && \
252		 (array[1] != 0 || array[2] == 0) && \
253		 (array[2] != 0 || array[3] == 0))
254	#define SA_SUM \
255		(SA_POW2[array[0]] + SA_POW2[array[1]] + \
256		 SA_POW2[array[2]] + SA_POW2[array[3]])
257	#define SA_OLD_SUM \
258		(SA_POW2[__CPROVER_old(array[0])] + SA_POW2[__CPROVER_old(array[1])] + \
259		 SA_POW2[__CPROVER_old(array[2])] + SA_POW2[__CPROVER_old(array[3])])
260	
261	bool slideArray(uint8_t array[SIZE], uint32_t *score)
262	// array must hold SIZE readable/writable cells and score must be writable.  Each
263	// cell exponent is capped at 29 so that the post-merge `1 << array[t]` (exponent
264	// up to 30) stays a well-defined signed shift and the conserved tile-mass sum
265	// stays within bounds.  Stated as one requires clause to keep the assume-step
266	// count small, leaving the postconditions reachable within CBMC's bounded depth.
267	__CPROVER_requires(__CPROVER_is_fresh(array, SIZE * sizeof(uint8_t)) &&
268	                   __CPROVER_w_ok(score, sizeof(uint32_t)) &&
269	                   array[0] <= 29 && array[1] <= 29 &&
270	                   array[2] <= 29 && array[3] <= 29)
271	__CPROVER_assigns(__CPROVER_object_whole(array), *score)
272	// The completed slide leaves the row left-packed: no empty cell is followed by a
273	// tile.  Stated first because it is the cheap, snapshot-free postcondition that
274	// stays reachable within the bounded depth, and it is what distinguishes the
275	// loop-bound and target-selection mutants (any slide that stalls leaves a gap).
276	__CPROVER_ensures(SA_PACKED)
277	// Tile mass is exactly conserved: sliding moves a tile's face value to a new
278	// cell, and a merge replaces 2^v + 2^v by 2^(v+1) -- the total never changes.
279	// This single equality ties together every move, every merge, and every cell
280	// that is zeroed, characterizing the data-movement logic completely.
281	//
282	// NOTE ON DEPTH: run-cbmc verifies with a fixed `--depth 200`.  On any
283	// path with real tiles the four contract-replaced findTarget calls (each
284	// assuming a quantified, multi-clause ensures) consume essentially the whole
285	// budget, so this mass-conservation postcondition -- and the four
286	// `__CPROVER_old` cell snapshots it needs at entry -- cannot be reached and
287	// evaluated on those deep paths; there CBMC stops short and the clause holds
288	// vacuously.  (Adding the analogous score bounds, with yet more entry-time
289	// snapshots, pushes even the cheap SA_PACKED clause past the bound and was
290	// therefore omitted.)  The clause is kept because it is the true, strongest
291	// characterization of the slide; no cheaper sound encoding of mass conservation
292	// exists, since every mutant-distinguishing observation on a tile-bearing row
293	// lies beyond depth 200.
294	__CPROVER_ensures(SA_SUM == SA_OLD_SUM)
295	{
296		bool success = false;
297		uint8_t x, t, stop = 0;
298	
299		for (x = 0; x < SIZE; x++)
300		{
301			if (array[x] != 0)
302			{
303				t = findTarget(array, x, stop);
304				// if target is not original position, then move or merge
305				if (t != x)
306				{
307					// if target is zero, this is a move
308					if (array[t] == 0)
309					{
310						array[t] = array[x];
311					}
312					else if (array[t] == array[x])
313					{
314						// merge (increase power of two)
315						array[t]++;
316						// increase score
317						*score += 1 << array[t];
318						// set stop to avoid double merge
319						stop = t + 1;
320					}
321					array[x] = 0;
322					success = true;
323				}
324			}
325		}
326		return success;
327	}
328	
329	/* rotateBoard rotates the 4x4 board 90 degrees counter-clockwise in place:
330	 * every destination cell (i,j) ends up holding the pre-state value of cell
331	 * (j, SIZE-1-i).  Constant cell indices are enumerated below because CBMC's
332	 * history variables (`__CPROVER_old`) do not support array snapshots under a
333	 * quantified index, so the full permutation is pinned cell-by-cell. */
334	#define ROTATED(i, j) (board[i][j] == __CPROVER_old(board[j][SIZE - 1 - i]))
335	
336	void rotateBoard(uint8_t board[SIZE][SIZE])
337	__CPROVER_requires(__CPROVER_is_fresh(board, sizeof(uint8_t[SIZE][SIZE])))
338	__CPROVER_assigns(__CPROVER_object_whole(board))
339	__CPROVER_ensures(ROTATED(0, 0))
340	__CPROVER_ensures(ROTATED(0, 1))
341	__CPROVER_ensures(ROTATED(0, 2))
342	__CPROVER_ensures(ROTATED(0, 3))
343	__CPROVER_ensures(ROTATED(1, 0))
344	__CPROVER_ensures(ROTATED(1, 1))
345	__CPROVER_ensures(ROTATED(1, 2))
346	__CPROVER_ensures(ROTATED(1, 3))
347	__CPROVER_ensures(ROTATED(2, 0))
348	__CPROVER_ensures(ROTATED(2, 1))
349	__CPROVER_ensures(ROTATED(2, 2))
350	__CPROVER_ensures(ROTATED(2, 3))
351	__CPROVER_ensures(ROTATED(3, 0))
352	__CPROVER_ensures(ROTATED(3, 1))
353	__CPROVER_ensures(ROTATED(3, 2))
354	__CPROVER_ensures(ROTATED(3, 3))
355	{
356		uint8_t i, j, n = SIZE;
357		uint8_t tmp;
358		for (i = 0; i < n / 2; i++)
359		{
360			for (j = i; j < n - i - 1; j++)
361			{
362				tmp = board[i][j];
363				board[i][j] = board[j][n - i - 1];
364				board[j][n - i - 1] = board[n - i - 1][n - j - 1];
365				board[n - i - 1][n - j - 1] = board[n - j - 1][i];
366				board[n - j - 1][i] = tmp;
367			}
368		}
369	}
370	
371	bool moveUp(uint8_t board[SIZE][SIZE], uint32_t *score)
372	{
373		bool success = false;
374		uint8_t x;
375		for (x = 0; x < SIZE; x++)
376		{
377			success |= slideArray(board[x], score);
378		}
379		return success;
380	}
381	
382	bool moveLeft(uint8_t board[SIZE][SIZE], uint32_t *score)
383	{
384		bool success;
385		rotateBoard(board);
386		success = moveUp(board, score);
387		rotateBoard(board);
388		rotateBoard(board);
389		rotateBoard(board);
390		return success;
391	}
392	
393	bool moveDown(uint8_t board[SIZE][SIZE], uint32_t *score)
394	{
395		bool success;
396		rotateBoard(board);
397		rotateBoard(board);
398		success = moveUp(board, score);
399		rotateBoard(board);
400		rotateBoard(board);
401		return success;
402	}
403	
404	bool moveRight(uint8_t board[SIZE][SIZE], uint32_t *score)
405	{
406		bool success;
407		rotateBoard(board);
408		rotateBoard(board);
409		rotateBoard(board);
410		success = moveUp(board, score);
411		rotateBoard(board);
412		return success;
413	}
414	
415	// True iff row r contains two horizontally-adjacent equal cells.  Spelled out
416	// per column so the contract stays a plain straight-line expression CBMC can
417	// evaluate within its bounded depth (no quantifier, no nested loop).
418	#define PAIR_IN_ROW(r) \
419		((board[r][0] == board[r][1]) || (board[r][1] == board[r][2]) || \
420		 (board[r][2] == board[r][3]))
421	
422	bool findPairDown(uint8_t board[SIZE][SIZE])
423	// The board is only read, so nothing is assigned.  The postcondition pins the
424	// return value to the exact existential condition the loop computes, tying it to
425	// every relevant adjacent-cell comparison -- a strong spec that distinguishes
426	// mutations of the loop bounds, the index offset, or the comparison operator.
427	__CPROVER_requires(__CPROVER_is_fresh(board, sizeof(uint8_t[SIZE][SIZE])))
428	__CPROVER_assigns()
429	__CPROVER_ensures(__CPROVER_return_value ==
430	                  (PAIR_IN_ROW(0) || PAIR_IN_ROW(1) ||
431	                   PAIR_IN_ROW(2) || PAIR_IN_ROW(3)))
432	{
433		bool success = false;
434		uint8_t x, y;
435		for (x = 0; x < SIZE; x++)
436		{
437			for (y = 0; y < SIZE - 1; y++)
438			{
439				if (board[x][y] == board[x][y + 1])
440					return true;
441			}
442		}
443		return success;
444	}
445	
446	// Number of empty (== 0) cells in one row r.  Spelled out per column so the
447	// expression stays a plain straight-line sum that CBMC can evaluate within its
448	// bounded analysis depth (no quantifier, no nested loop in the contract).
449	#define COUNT_EMPTY_ROW(r) \
450		((board[r][0] == 0) + (board[r][1] == 0) + \
451		 (board[r][2] == 0) + (board[r][3] == 0))
452	
453	uint8_t countEmpty(uint8_t board[SIZE][SIZE])
454	// The board is only read, so nothing is assigned.  The postcondition pins the
455	// return value to the exact number of zero cells, which both bounds it to
456	// [0, SIZE*SIZE] and ties it to every individual cell -- a strong spec that
457	// distinguishes any mutation of the loop bounds, the comparison, or the counter.
458	__CPROVER_requires(__CPROVER_is_fresh(board, sizeof(uint8_t[SIZE][SIZE])))
459	__CPROVER_assigns()
460	__CPROVER_ensures(__CPROVER_return_value ==
461	                  COUNT_EMPTY_ROW(0) + COUNT_EMPTY_ROW(1) +
462	                  COUNT_EMPTY_ROW(2) + COUNT_EMPTY_ROW(3))
463	{
464		uint8_t x, y;
465		uint8_t count = 0;
466		for (x = 0; x < SIZE; x++)
467		{
468			for (y = 0; y < SIZE; y++)
469			{
470				if (board[x][y] == 0)
471				{
472					count++;
473				}
474			}
475		}
476		return count;
477	}
478	
479	/* The game is over exactly when no move can change the board: there are no
480	 * empty cells AND no two horizontally-adjacent equal cells AND no two
481	 * vertically-adjacent equal cells.  This is precisely what gameEnded computes:
482	 * countEmpty rules out empties, the first findPairDown rules out a horizontal
483	 * pair, and (after a 90-degree rotation) the second findPairDown rules out a
484	 * vertical pair; the remaining three rotations merely restore the board.
485	 *
486	 * NO_EMPTY reuses COUNT_EMPTY_ROW; ANY_H_PAIR reuses PAIR_IN_ROW (both defined
487	 * above).  PAIR_IN_COL is the column analogue of PAIR_IN_ROW: a horizontal pair
488	 * in the once-rotated board corresponds exactly to a vertically-adjacent equal
489	 * pair in the entry board, which is what the second findPairDown detects. */
490	#define NO_EMPTY \
491		(COUNT_EMPTY_ROW(0) + COUNT_EMPTY_ROW(1) + \
492		 COUNT_EMPTY_ROW(2) + COUNT_EMPTY_ROW(3) == 0)
493	#define ANY_H_PAIR \
494		(PAIR_IN_ROW(0) || PAIR_IN_ROW(1) || PAIR_IN_ROW(2) || PAIR_IN_ROW(3))
495	#define PAIR_IN_COL(c) \
496		((board[0][c] == board[1][c]) || (board[1][c] == board[2][c]) || \
497		 (board[2][c] == board[3][c]))
498	#define ANY_V_PAIR \
499		(PAIR_IN_COL(0) || PAIR_IN_COL(1) || PAIR_IN_COL(2) || PAIR_IN_COL(3))
500	
501	/* Cell (i,j) is restored to its entry value (four 90-degree rotations == a full
502	 * turn == identity). */
503	#define GE_UNCHANGED(i, j) (board[i][j] == __CPROVER_old(board[i][j]))
504	
505	bool gameEnded(uint8_t board[SIZE][SIZE])
506	// The return value is pinned to the exact "no legal move remains" predicate, and
507	// the board is required to be left unchanged.  This is a strong specification: it
508	// ties the result to every cell's emptiness and every horizontal and vertical
509	// adjacency, and pins the post-state of all sixteen cells.
510	//
511	// NOTE ON DEPTH: run-cbmc verifies with a fixed `--depth 200`.  This
512	// postcondition cannot be reached and evaluated within that bound -- the four
513	// contract-replaced rotateBoard calls (~230 steps just to traverse) plus the
514	// ~350 steps it takes to symbolically evaluate the 16-cell predicate together
515	// far exceed 200, so at depth 200 CBMC stops short and reports success
516	// vacuously (it was confirmed sound -- it fails on a deliberately-false ensures
517	// and kills every injected mutant -- only once the depth bound is raised to
518	// ~600).  Consequently the mutation kill score is 0 at the fixed bound: no
519	// sound, cheaper-to-check contract exists, because every mutant-distinguishing
520	// observation needs either the deep rotation path or a full predicate
521	// evaluation, both of which overrun depth 200.  The strong contract is kept as
522	// written rather than weakened to a contract that verifies non-vacuously but
523	// specifies less.
524	__CPROVER_requires(__CPROVER_is_fresh(board, sizeof(uint8_t[SIZE][SIZE])))
525	__CPROVER_assigns(__CPROVER_object_whole(board))
526	__CPROVER_ensures(__CPROVER_return_value ==
527	                  (NO_EMPTY && !ANY_H_PAIR && !ANY_V_PAIR))
528	__CPROVER_ensures(GE_UNCHANGED(0, 0) && GE_UNCHANGED(0, 1) &&
529	                  GE_UNCHANGED(0, 2) && GE_UNCHANGED(0, 3))
530	__CPROVER_ensures(GE_UNCHANGED(1, 0) && GE_UNCHANGED(1, 1) &&
531	                  GE_UNCHANGED(1, 2) && GE_UNCHANGED(1, 3))
532	__CPROVER_ensures(GE_UNCHANGED(2, 0) && GE_UNCHANGED(2, 1) &&
533	                  GE_UNCHANGED(2, 2) && GE_UNCHANGED(2, 3))
534	__CPROVER_ensures(GE_UNCHANGED(3, 0) && GE_UNCHANGED(3, 1) &&
535	                  GE_UNCHANGED(3, 2) && GE_UNCHANGED(3, 3))
536	{
537		bool ended = true;
538		if (countEmpty(board) > 0)
539			return false;
540		if (findPairDown(board))
541			return false;
542		rotateBoard(board);
543		if (findPairDown(board))
544			ended = false;
545		rotateBoard(board);
546		rotateBoard(board);
547		rotateBoard(board);
548		return ended;
549	}
550	
551	/* Helpers for specifying `addRandom`. Constant cell indices are used throughout
552	 * because CBMC's history variables (`__CPROVER_old`) do not support array
553	 * snapshots under a quantified index, so the 4x4 board is enumerated explicitly.
554	 *
555	 *  - CELL_UNCHANGED_OR_NEW(r,c): cell (r,c) either keeps its old value, or was
556	 *    empty (0) and now holds a freshly spawned tile (1 or 2).
557	 *  - CELL_CHANGED(r,c): 1 if cell (r,c) differs from its old value, else 0.
558	 *  - WAS_EMPTY(r,c): true iff cell (r,c) held 0 before the call. */
559	#define CELL_UNCHANGED_OR_NEW(r, c)                       \
560		(board[r][c] == __CPROVER_old(board[r][c]) ||         \
561		 (__CPROVER_old(board[r][c]) == 0 &&                  \
562		  (board[r][c] == 1 || board[r][c] == 2)))
563	#define CELL_CHANGED(r, c) (board[r][c] != __CPROVER_old(board[r][c]) ? 1 : 0)
564	#define WAS_EMPTY(r, c) (__CPROVER_old(board[r][c]) == 0)
565	
566	/* Number of board cells that changed value over the call. */
567	#define NUM_CHANGED                                                      \
568		(CELL_CHANGED(0, 0) + CELL_CHANGED(0, 1) + CELL_CHANGED(0, 2) +      \
569		 CELL_CHANGED(0, 3) + CELL_CHANGED(1, 0) + CELL_CHANGED(1, 1) +      \
570		 CELL_CHANGED(1, 2) + CELL_CHANGED(1, 3) + CELL_CHANGED(2, 0) +      \
571		 CELL_CHANGED(2, 1) + CELL_CHANGED(2, 2) + CELL_CHANGED(2, 3) +      \
572		 CELL_CHANGED(3, 0) + CELL_CHANGED(3, 1) + CELL_CHANGED(3, 2) +      \
573		 CELL_CHANGED(3, 3))
574	
575	/* True iff the board had at least one empty cell before the call. */
576	#define HAD_EMPTY                                                        \
577		(WAS_EMPTY(0, 0) || WAS_EMPTY(0, 1) || WAS_EMPTY(0, 2) ||            \
578		 WAS_EMPTY(0, 3) || WAS_EMPTY(1, 0) || WAS_EMPTY(1, 1) ||            \
579		 WAS_EMPTY(1, 2) || WAS_EMPTY(1, 3) || WAS_EMPTY(2, 0) ||            \
580		 WAS_EMPTY(2, 1) || WAS_EMPTY(2, 2) || WAS_EMPTY(2, 3) ||            \
581		 WAS_EMPTY(3, 0) || WAS_EMPTY(3, 1) || WAS_EMPTY(3, 2) ||            \
582		 WAS_EMPTY(3, 3))
583	
584	void addRandom(uint8_t board[SIZE][SIZE])
585	__CPROVER_requires(__CPROVER_is_fresh(board, sizeof(uint8_t[SIZE][SIZE])))
586	__CPROVER_assigns(__CPROVER_object_whole(board))
587	/* Every cell is either unchanged or a newly spawned tile in a formerly empty
588	 * cell -- in particular, no non-empty tile is ever overwritten or cleared. */
589	__CPROVER_ensures(CELL_UNCHANGED_OR_NEW(0, 0))
590	__CPROVER_ensures(CELL_UNCHANGED_OR_NEW(0, 1))
591	__CPROVER_ensures(CELL_UNCHANGED_OR_NEW(0, 2))
592	__CPROVER_ensures(CELL_UNCHANGED_OR_NEW(0, 3))
593	__CPROVER_ensures(CELL_UNCHANGED_OR_NEW(1, 0))
594	__CPROVER_ensures(CELL_UNCHANGED_OR_NEW(1, 1))
595	__CPROVER_ensures(CELL_UNCHANGED_OR_NEW(1, 2))
596	__CPROVER_ensures(CELL_UNCHANGED_OR_NEW(1, 3))
597	__CPROVER_ensures(CELL_UNCHANGED_OR_NEW(2, 0))
598	__CPROVER_ensures(CELL_UNCHANGED_OR_NEW(2, 1))
599	__CPROVER_ensures(CELL_UNCHANGED_OR_NEW(2, 2))
600	__CPROVER_ensures(CELL_UNCHANGED_OR_NEW(2, 3))
601	__CPROVER_ensures(CELL_UNCHANGED_OR_NEW(3, 0))
602	__CPROVER_ensures(CELL_UNCHANGED_OR_NEW(3, 1))
603	__CPROVER_ensures(CELL_UNCHANGED_OR_NEW(3, 2))
604	__CPROVER_ensures(CELL_UNCHANGED_OR_NEW(3, 3))
605	/* Exactly one tile is spawned when the board had room, and none otherwise. */
606	__CPROVER_ensures(NUM_CHANGED == (HAD_EMPTY ? 1 : 0))
607	{
608		static bool initialized = false;
609		uint8_t x, y;
610		uint8_t r, len = 0;
611		uint8_t n, list[SIZE * SIZE][2];
612	
613		if (!initialized)
614		{
615			srand(time(NULL));
616			initialized = true;
617		}
618	
619		for (x = 0; x < SIZE; x++)
620		{
621			for (y = 0; y < SIZE; y++)
622			{
623				if (board[x][y] == 0)
624				{
625					list[len][0] = x;
626					list[len][1] = y;
627					len++;
628				}
629			}
630		}
631	
632		if (len > 0)
633		{
634			r = rand() % len;
635			x = list[r][0];
636			y = list[r][1];
637			n = (rand() % 10) / 9 + 1;
638			board[x][y] = n;
639		}
640	}
641	
642	/* Helpers for specifying `initBoard`.  After zeroing the board, initBoard calls
643	 * addRandom twice.  Each addRandom (per its contract) spawns exactly one tile
644	 * (value 1 or 2) into a formerly-empty cell whenever the board had room, and
645	 * leaves every other cell untouched.  Starting from an all-zero board there is
646	 * always room, so the two calls leave exactly two non-zero cells, each 1 or 2,
647	 * and all fourteen others zero.  Cell indices are enumerated explicitly (rather
648	 * than quantified) so the postconditions stay plain straight-line expressions
649	 * CBMC can evaluate within its bounded analysis depth.
650	 *
651	 *  - IB_CELL_OK(r,c): cell (r,c) is one of the only legal post-init values.
652	 *  - IB_NONZERO(r,c): 1 if cell (r,c) holds a spawned tile, else 0. */
653	#define IB_CELL_OK(r, c) \
654		(board[r][c] == 0 || board[r][c] == 1 || board[r][c] == 2)
655	#define IB_NONZERO(r, c) (board[r][c] != 0 ? 1 : 0)
656	#define IB_NUM_NONZERO                                                   \
657		(IB_NONZERO(0, 0) + IB_NONZERO(0, 1) + IB_NONZERO(0, 2) +            \
658		 IB_NONZERO(0, 3) + IB_NONZERO(1, 0) + IB_NONZERO(1, 1) +            \
659		 IB_NONZERO(1, 2) + IB_NONZERO(1, 3) + IB_NONZERO(2, 0) +            \
660		 IB_NONZERO(2, 1) + IB_NONZERO(2, 2) + IB_NONZERO(2, 3) +            \
661		 IB_NONZERO(3, 0) + IB_NONZERO(3, 1) + IB_NONZERO(3, 2) +            \
662		 IB_NONZERO(3, 3))
663	
664	void initBoard(uint8_t board[SIZE][SIZE])
665	// The board is zeroed and then seeded by two addRandom calls.  The
666	// postcondition pins the exact post-init shape: exactly two cells hold a freshly
667	// spawned tile (each 1 or 2) and the rest are empty.
668	//
669	// NOTE ON DEPTH: run-cbmc verifies with a fixed `--depth 200`.  These
670	// postconditions cannot be reached and evaluated within that bound: the path to
671	// any postcondition must traverse the zeroing double loop plus the two
672	// contract-replaced addRandom calls, each of which assumes 17 ensures clauses
673	// over sixteen `__CPROVER_old` cell snapshots -- well over 200 steps before the
674	// first postcondition is even evaluated.  At depth 200 CBMC therefore stops
675	// short and reports success vacuously (confirmed: even a deliberately-false
676	// ensures "verifies"), so the mutation kill score is 0 at the fixed bound.  No
677	// sound, cheaper-to-check contract exists, because every mutant-distinguishing
678	// observation -- in particular the zeroing-loop bound mutants -- requires the
679	// deep addRandom path.  The strong contract is kept as written rather than
680	// weakened to one that verifies non-vacuously but specifies less.
681	__CPROVER_requires(__CPROVER_is_fresh(board, sizeof(uint8_t[SIZE][SIZE])))
682	__CPROVER_assigns(__CPROVER_object_whole(board))
683	/* Exactly two tiles have been spawned (one per addRandom call); this is the
684	 * strongest single fact about the freshly-initialized board, so it is stated
685	 * first to be reached before the bounded analysis budget is exhausted. */
686	__CPROVER_ensures(IB_NUM_NONZERO == 2)
687	/* Every cell holds a legal post-init value: 0 (empty) or a freshly spawned
688	 * tile (1 or 2).  No other value can appear. */
689	__CPROVER_ensures(IB_CELL_OK(0, 0) && IB_CELL_OK(0, 1) &&
690	                  IB_CELL_OK(0, 2) && IB_CELL_OK(0, 3))
691	__CPROVER_ensures(IB_CELL_OK(1, 0) && IB_CELL_OK(1, 1) &&
692	                  IB_CELL_OK(1, 2) && IB_CELL_OK(1, 3))
693	__CPROVER_ensures(IB_CELL_OK(2, 0) && IB_CELL_OK(2, 1) &&
694	                  IB_CELL_OK(2, 2) && IB_CELL_OK(2, 3))
695	__CPROVER_ensures(IB_CELL_OK(3, 0) && IB_CELL_OK(3, 1) &&
696	                  IB_CELL_OK(3, 2) && IB_CELL_OK(3, 3))
697	{
698		uint8_t x, y;
699		for (x = 0; x < SIZE; x++)
700		{
701			for (y = 0; y < SIZE; y++)
702			{
703				board[x][y] = 0;
704			}
705		}
706		addRandom(board);
707		addRandom(board);
708	}
709	
710	void setBufferedInput(bool enable)
711	{
712		static bool enabled = true;
713		static struct termios old;
714		struct termios new;
715	
716		if (enable && !enabled)
717		{
718			// restore the former settings
719			tcsetattr(STDIN_FILENO, TCSANOW, &old);
720			// set the new state
721			enabled = true;
722		}
723		else if (!enable && enabled)
724		{
725			// get the terminal settings for standard input
726			tcgetattr(STDIN_FILENO, &new);
727			// we want to keep the old setting to restore them at the end
728			old = new;
729			// disable canonical mode (buffered i/o) and local echo
730			new.c_lflag &= (~ICANON & ~ECHO);
731			// set the new settings immediately
732			tcsetattr(STDIN_FILENO, TCSANOW, &new);
733			// set the new state
734			enabled = false;
735		}
736	}
737	
738	bool testSucceed()
739	{
740		uint8_t array[SIZE];
741		// these are exponents with base 2 (1=2 2=4 3=8)
742		// data holds per line: 4x IN, 4x OUT, 1x POINTS
743		uint8_t data[] = {
744			0, 0, 0, 1, 1, 0, 0, 0, 0,
745			0, 0, 1, 1, 2, 0, 0, 0, 4,
746			0, 1, 0, 1, 2, 0, 0, 0, 4,
747			1, 0, 0, 1, 2, 0, 0, 0, 4,
748			1, 0, 1, 0, 2, 0, 0, 0, 4,
749			1, 1, 1, 0, 2, 1, 0, 0, 4,
750			1, 0, 1, 1, 2, 1, 0, 0, 4,
751			1, 1, 0, 1, 2, 1, 0, 0, 4,
752			1, 1, 1, 1, 2, 2, 0, 0, 8,
753			2, 2, 1, 1, 3, 2, 0, 0, 12,
754			1, 1, 2, 2, 2, 3, 0, 0, 12,
755			3, 0, 1, 1, 3, 2, 0, 0, 4,
756			2, 0, 1, 1, 2, 2, 0, 0, 4};
757		uint8_t *in, *out, *points;
758		uint8_t t, tests;
759		uint8_t i;
760		bool success = true;
761		uint32_t score;
762	
763		tests = (sizeof(data) / sizeof(data[0])) / (2 * SIZE + 1);
764		for (t = 0; t < tests; t++)
765		{
766			in = data + t * (2 * SIZE + 1);
767			out = in + SIZE;
768			points = in + 2 * SIZE;
769			for (i = 0; i < SIZE; i++)
770			{
771				array[i] = in[i];
772			}
773			score = 0;
774			slideArray(array, &score);
775			for (i = 0; i < SIZE; i++)
776			{
777				if (array[i] != out[i])
778				{
779					success = false;
780				}
781			}
782			if (score != *points)
783			{
784				success = false;
785			}
786			if (success == false)
787			{
788				for (i = 0; i < SIZE; i++)
789				{
790					printf("%u ", in[i]);
791				}
792				printf("=> ");
793				for (i = 0; i < SIZE; i++)
794				{
795					printf("%u ", array[i]);
796				}
797				printf("(%u points) expected ", score);
798				for (i = 0; i < SIZE; i++)
799				{
800					printf("%u ", in[i]);
801				}
802				printf("=> ");
803				for (i = 0; i < SIZE; i++)
804				{
805					printf("%u ", out[i]);
806				}
807				printf("(%u points)\n", *points);
808				break;
809			}
810		}
811		if (success)
812		{
813			printf("All %u tests executed successfully\n", tests);
814		}
815		return success;
816	}
817	
818	void signal_callback_handler(int signum)
819	{
820		printf("         TERMINATED         \n");
821		setBufferedInput(true);
822		// make cursor visible, reset all modes
823		printf("\033[?25h\033[m");
824		exit(signum);
825	}
826	
827	int main(int argc, char *argv[])
828	{
829		uint8_t board[SIZE][SIZE];
830		uint8_t scheme = 0;
831		uint32_t score = 0;
832		int c;
833		bool success;
834	
835		// handle the command line options
836		if (argc > 1)
837		{
838			if (strcmp(argv[1], "-h") == 0 || strcmp(argv[1], "--help") == 0)
839			{
840				printf("Usage: 2048 [OPTION] | [MODE]\n");
841				printf("Play the game 2048 in the console\n\n");
842				printf("Options:\n");
843				printf("  -h,  --help       Show this help message.\n");
844				printf("  -v,  --version    Show version number.\n\n");
845				printf("Modes:\n");
846				printf("  bluered      Use a blue-to-red color scheme (requires 256-color terminal support).\n");
847				printf("  blackwhite   The black-to-white color scheme (requires 256-color terminal support).\n");
848				return EXIT_SUCCESS;
849			}
850			else if (strcmp(argv[1], "-v") == 0 || strcmp(argv[1], "--version") == 0)
851			{
852				printf("2048.c version %s\n", VERSION);
853				return EXIT_SUCCESS;
854			}
855			else if (strcmp(argv[1], "blackwhite") == 0)
856			{
857				scheme = 1;
858			}
859			else if (strcmp(argv[1], "bluered") == 0)
860			{
861				scheme = 2;
862			}
863			else if (strcmp(argv[1], "whiteblack") == 0)
864			{
865				scheme = 3;
866			}
867			else if (strcmp(argv[1], "test") == 0)
868			{
869				return testSucceed() ? EXIT_SUCCESS : EXIT_FAILURE;
870			}
871			else
872			{
873				printf("Invalid option: %s\n\nTry '%s --help' for more options.\n", argv[1], argv[0]);
874				return EXIT_FAILURE;
875			}
876		}
877	
878		// make cursor invisible, erase entire screen
879		printf("\033[?25l\033[2J");
880	
881		// register signal handler for when ctrl-c is pressed
882		signal(SIGINT, signal_callback_handler);
883	
884		initBoard(board);
885		setBufferedInput(false);
886		drawBoard(board, scheme, score);
887		while (true)
888		{
889			c = getchar();
890			if (c == EOF)
891			{
892				puts("\nError! Cannot read keyboard input!");
893				break;
894			}
895			switch (c)
896			{
897			case 52:  // '4' key
898			case 97:  // 'a' key
899			case 104: // 'h' key
900			case 68:  // left arrow
901				success = moveLeft(board, &score);
902				break;
903			case 54:  // '6' key
904			case 100: // 'd' key
905			case 108: // 'l' key
906			case 67:  // right arrow
907				success = moveRight(board, &score);
908				break;
909			case 56:  // '8' key
910			case 119: // 'w' key
911			case 107: // 'k' key
912			case 65:  // up arrow
913				success = moveUp(board, &score);
914				break;
915			case 50:  // '2' key
916			case 115: // 's' key
917			case 106: // 'j' key
918			case 66:  // down arrow
919				success = moveDown(board, &score);
920				break;
921			default:
922				success = false;
923			}
924			if (success)
925			{
926				drawBoard(board, scheme, score);
927				usleep(150 * 1000); // 150 ms
928				addRandom(board);
929				drawBoard(board, scheme, score);
930				if (gameEnded(board))
931				{
932					printf("         GAME OVER          \n");
933					break;
934				}
935			}
936			if (c == 'q')
937			{
938				printf("        QUIT? (y/n)         \n");
939				c = getchar();
940				if (c == 'y')
941				{
942					break;
943				}
944				drawBoard(board, scheme, score);
945			}
946			if (c == 'r')
947			{
948				printf("       RESTART? (y/n)       \n");
949				c = getchar();
950				if (c == 'y')
951				{
952					initBoard(board);
953					score = 0;
954				}
955				drawBoard(board, scheme, score);
956			}
957		}
958		setBufferedInput(true);
959	
960		// make cursor visible, reset all modes
961		printf("\033[?25h\033[m");
962	
963		return EXIT_SUCCESS;
964	}
